import {
  MARKER_HALF_WIDTH,
  SQUARE_HEIGHT,
  TRIANGLE_HEIGHT,
  VALUE_MARKER_WIDTH,
} from '../constants.js';

export const calculateCenterMarkerVertexes = (
  x: number,
  y: number,
  width: number,
) => {
  const halfWidth = width / 2;
  const leftXValues = x - halfWidth;
  const rightXValues = x + halfWidth;
  const bottomYValues = y + SQUARE_HEIGHT;

  const bottomCenterVertex = { x, y: bottomYValues + TRIANGLE_HEIGHT };
  const triangleBottomLeftJoint = {
    x: x - MARKER_HALF_WIDTH,
    y: bottomYValues,
  };
  const topLeftVertex = { x: leftXValues, y };
  const topRightVertex = { x: rightXValues, y };
  const triangleBottomRightJoint = {
    x: x + MARKER_HALF_WIDTH,
    y: bottomYValues,
  };

  const shape = [
    bottomCenterVertex,
    triangleBottomLeftJoint,
    topLeftVertex,
    topRightVertex,
    triangleBottomRightJoint,
  ];

  if (width !== VALUE_MARKER_WIDTH) {
    const bottomLeftVertex = { x: leftXValues, y: bottomYValues };
    const bottomRightVertex = { x: rightXValues, y: bottomYValues };
    shape.splice(2, 0, bottomLeftVertex);
    shape.splice(5, 0, bottomRightVertex);
  }

  return shape;
};
